const body = $json;
if (body.benefit_type !== 'CPQ_Maturity_scan') return [{ json: { success: false, error_code: 'INVALID_INPUT', message: 'benefit_type must be CPQ_Maturity_scan' } }];
const configAutomation = Number(body.answers.configuration_automation ?? body.answers.question_1 ?? 0);
const pricingGovernance = Number(body.answers.pricing_governance ?? body.answers.question_2 ?? 0);
const engineeringCollab = Number(body.answers.engineering_collaboration ?? body.answers.question_3 ?? 0);
const approvals = Number(body.answers.approval_workflows ?? body.answers.question_4 ?? 0);
if (![configAutomation, pricingGovernance, engineeringCollab, approvals].every(Number.isFinite)) {
 return [{ json: { success: false, error_code: 'INVALID_INPUT', message: 'All maturity signals must be numeric' } }];
}
return [{ json: { ...body, maturity_inputs: { configAutomation, pricingGovernance, engineeringCollab, approvals } } }];

if ($json.success === false) return [{ json: $json }];
const { configAutomation, pricingGovernance, engineeringCollab, approvals } = $json.maturity_inputs;
const maturityRaw = (configAutomation + pricingGovernance + engineeringCollab + approvals) / 4;
const maturity_level = Math.max(1, Math.min(5, Math.round(maturityRaw / 20)));
const score = maturity_level * 20;
const priorities = ['Data quality baselining', 'Rules and pricing governance', 'Cross-functional workflow automation'];
return [{ json: { ...$json, maturity_level, score, priorities } }];

if ($json.success === false) return [{ json: $json }];
return [{
  json: {
    success: true,
    benefit_type: 'CPQ_Maturity_scan',
    score: $json.score,
    summary: `CPQ maturity level is ${$json.maturity_level}/5. Focus on ${$json.priorities[0].toLowerCase()}.`,
    recommendations: $json.priorities,
    meta: {
      execution_id: $execution.id,
      version: '1.0.0',
      benefit_version: '2026-Q1',
      maturity_level: $json.maturity_level,
      improvement_priority: $json.priorities[0]
    }
  }
}];
